   104|    const padded = normalized + '='.repeat((4 - (normalized.length % 4)) % 4);
   105|    const decoded =
   106|      typeof atob === 'function' ? atob(padded) : Buffer.from(padded, 'base64').toString('utf8');
   107|    return JSON.parse(decoded) as DecodedJwt;
   108|  } catch {
   109|    return null;
   110|  }
