   310|        ok: false,
   311|        label: OWNER_SESSION_REQUIRED_LABEL,
   312|        reason: 'token_expired',
   313|        detail: 'The session token is expired. Sign in as the IVX owner and retry.',
   314|        email: sessionEmail,
   315|        checks,
   316|      };
   317|    }
   318|    checks.push({
   319|      id: 'token_validity',
   320|      passed: true,
   321|      detail:
   322|        secondsUntilExpiry !== null ? `Token valid (expires in ${secondsUntilExpiry}s).` : 'Token format valid.',
   323|    });
